// feed-content-pools-mega.ts
// MEGA expansion: 1400+ extra images, 150 extra users,
// 40+ extra captions per category — prevents 10-hour repetition
// ============================================================

// ─── ANTI-REPEAT IMAGE TRACKER ────────────────────────────────
const _usedImgQueue: string[] = [];
const _usedImgSet = new Set<string>();
const ANTI_REPEAT_WINDOW = 900;

export function pickFreshImage(pool: string[]): string {
  const fresh = pool.filter(u => !_usedImgSet.has(u));
  const chosen = fresh.length > 0
    ? fresh[Math.floor(Math.random() * fresh.length)]
    : pool[Math.floor(Math.random() * pool.length)];
  _usedImgSet.add(chosen);
  _usedImgQueue.push(chosen);
  if (_usedImgQueue.length > ANTI_REPEAT_WINDOW) {
    const evicted = _usedImgQueue.shift()!;
    _usedImgSet.delete(evicted);
  }
  return chosen;
}

export function pickFreshImages(pool: string[], count: number): string[] {
  const results: string[] = [];
  for (let i = 0; i < count; i++) results.push(pickFreshImage(pool));
  return results;
}

